   percentiles := []float64{25.0, 50.0, 75.0}
   desc, err := stats.Describe(data, true, &percentiles)
   if err != nil {
       t.Fatalf("Expected no error, got %v", err)
   }
   if len(desc.DescriptionPercentiles) != 3 {
       t.Fatalf("Expected 3 percentiles, got %d", len(desc.DescriptionPercentiles))
   }
   expected := []float64{math.NaN(), 1.5, 2.5}
   for i, dp := range desc.DescriptionPercentiles {
       exp := expected[i]
       if math.IsNaN(exp) {
           if !math.IsNaN(dp.Value) {
               t.Errorf("Expected NaN at index %d, got %v", i, dp.Value)
           }
       } else if dp.Value != exp {
           t.Errorf("Expected %v at index %d, got %v", exp, i, dp.Value)
       }
   }
}

