func TestNormalizeEmpty(t *testing.T) {
   in := Float64Data{}
   _, err := normalize(in)
   if err == nil {
       t.Error("normalize(empty) did not return error")
   }
}

// TestNormalizeZeroSum tests behavior when sum is zero
func TestNormalizeZeroSum(t *testing.T) {
   in := Float64Data{0.0, 0.0}
   out, err := normalize(in)
   if err != nil {
       t.Fatalf("normalize returned error: %v", err)
   }
   for i, v := range out {
       if !(math.IsInf(v, 0) || math.IsNaN(v)) {
           t.Errorf("out[%d] = %v; want Inf or NaN", i, v)
       }
   }
}

